units.exampleCode:
#include <iostream>
using namespace std;

void swap(int &a, int &b) {
    int temp = a;
    a = b;
    b = temp;
}

int main() {
    int x = 3, y = 7;
    cout << "交换前：x=" << x << " y=" << y << endl;
    swap(x, y);
    cout << "交换后：x=" << x << " y=" << y << endl;
    return 0;
}

